arguments.file_text:
@page "/chat"
@layout ChatLayout
@using sv_6252245f566d4c75895cc43e3639ad43.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<div class="chat-container">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h2>Channels</h2>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h3># @_activeChannel.Name</h3>
                <span class="channel-description">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="OnMessageScroll" @ref="_messageListRef">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-item" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-meta">
                                <span class="message-author">@msg.Author</span>
                                <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions?.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in msg.Reactions)
                                    {
                                        <button class="reaction-badge"
                                                @onclick="() => AddReactionAsync(msg.Id, reaction.Emoji)"
                                                title="@string.Join(", ", reaction.Users)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread starter link *@
                            @if (GetThreadSummary(msg.Id) is { } thread)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                    💬 @thread.ReplyCount @(thread.ReplyCount == 1 ? "reply" : "replies")
                                    <span class="thread-last-reply">
                                        — last reply @FormatRelativeTime(thread.LastReplyAt)
                                    </span>
                                </button>
                            }

                            @* Hover actions *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(msg.Id)"
                                            title="Reply in thread">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)"
                                                title="Add reaction">
                                            😀 React
                                        </button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" @bind="_newMessageText" @bind:event="oninput"
                          placeholder="Message #@_activeChannel.Name"
                          @onkeydown="OnMessageKeyDown"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <div class="message-meta">
                    <span class="message-author">@_threadRootMessage.Author</span>
                    <span class="message-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                </div>
                <div class="message-content">@_threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="message-item thread-reply-item">
                            <div class="message-meta">
                                <span class="message-author">@reply.Author</span>
                                <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>

                            @if (reply.Reactions?.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <button class="reaction-badge"
                                                @onclick="() => AddReactionAsync(reply.Id, reaction.Emoji)"
                                                title="@string.Join(", ", reaction.Users)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" @bind="_threadReplyText" @bind:event="oninput"
                          placeholder="Reply…"
                          @onkeydown="OnThreadReplyKeyDown"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private List<Channel>? _channels;
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private string _newMessageText = string.Empty;
    private bool _loadingMore;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread panel
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReplyText = string.Empty;
    private int? _activeThreadRootId;

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels?.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messages = null;

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;

        await ChatService.MarkChannelReadAsync(channel.Id);
        await BuildThreadSummariesAsync();

        // Refresh channels to update unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task BuildThreadSummariesAsync()
    {
        _threadSummaries.Clear();
        if (_messages is null) return;

        // Identify messages that have replies (messages where ReplyToId points to another message)
        var rootIds = _messages
            .Where(m => m.ReplyToId.HasValue)
            .Select(m => m.ReplyToId!.Value)
            .Distinct()
            .ToHashSet();

        // Also check messages that are themselves roots (others reply to them)
        foreach (var rootId in rootIds)
        {
            var replies = _messages.Where(m => m.ReplyToId == rootId).ToList();
            if (replies.Count > 0)
            {
                _threadSummaries[rootId] = new ThreadSummary(
                    rootId,
                    replies.Count,
                    replies.Max(r => r.SentAt));
            }
        }

        // Also fetch thread data from the service for root messages to catch replies
        // not yet loaded in the current page
        foreach (var msg in _messages.Where(m => m.ReplyToId is null))
        {
            if (!_threadSummaries.ContainsKey(msg.Id))
            {
                try
                {
                    var thread = await ChatService.GetThreadAsync(msg.Id);
                    if (thread.Count > 0)
                    {
                        _threadSummaries[msg.Id] = new ThreadSummary(
                            msg.Id,
                            thread.Count,
                            thread.Max(r => r.SentAt));
                    }
                }
                catch
                {
                    // Thread may not exist — that's fine
                }
            }
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        return _threadSummaries.GetValueOrDefault(messageId);
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingMore || _messages is null || _activeChannel is null) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.AddRange(older);
        }

        _loadingMore = false;
    }

    private async Task OnMessageScroll(EventArgs e)
    {
        // Scroll-to-top triggers loading older messages.
        // Because Blazor doesn't expose scrollTop directly in EventArgs, we use a simple
        // approach: the JS interop–free fallback loads on any scroll event when near top.
        // For a production app you'd use JS interop to check scrollTop === 0.
        // Here we allow the user to click a "load more" or we rely on the action.
        await Task.CompletedTask;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannel.Id, _newMessageText.Trim(), null);
        _messages ??= new();
        _messages.Insert(0, sent);
        _newMessageText = string.Empty;
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        _activeThreadRootId = rootMessageId;
        _threadRootMessage = _messages?.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadReplyText = string.Empty;
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _activeThreadRootId = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _activeChannel is null || _activeThreadRootId is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, _threadReplyText.Trim(), _activeThreadRootId);
        _threadReplies ??= new();
        _threadReplies.Add(reply);
        _threadReplyText = string.Empty;

        // Update thread summary
        _threadSummaries[_activeThreadRootId.Value] = new ThreadSummary(
            _activeThreadRootId.Value,
            _threadReplies.Count,
            reply.SentAt);
    }

    private async Task OnThreadReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (_activeChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _messages?.Count ?? PageSize);
        }

        // Refresh thread if open
        if (_threadOpen && _activeThreadRootId is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_activeThreadRootId.Value);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 172800 => "yesterday",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 50 ? string.Concat(description.AsSpan(0, 47), "...") : description;
    }
}

