using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Web;
using sv_6252245f566d4c75895cc43e3639ad43.Services;

namespace sv_6252245f566d4c75895cc43e3639ad43.Components.Pages;

public partial class Chat
{
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    [Inject] private IChatService ChatService { get; set; } = default!;

    private List<Channel>? _channels;
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private string _newMessageText = string.Empty;
    private bool _loadingMore;
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread panel
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReplyText = string.Empty;
    private int? _activeThreadRootId;

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels?.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messages = null;

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;

        await ChatService.MarkChannelReadAsync(channel.Id);
        await BuildThreadSummariesAsync();

        // Refresh channels to update unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task BuildThreadSummariesAsync()
    {
        _threadSummaries.Clear();
        if (_messages is null) return;

        var rootIds = _messages
            .Where(m => m.ReplyToId.HasValue)
            .Select(m => m.ReplyToId!.Value)
            .Distinct()
            .ToHashSet();

        foreach (var rootId in rootIds)
        {
            var replies = _messages.Where(m => m.ReplyToId == rootId).ToList();
            if (replies.Count > 0)
            {
                _threadSummaries[rootId] = new ThreadSummary(
                    rootId,
                    replies.Count,
                    replies.Max(r => r.SentAt));
            }
        }

        // Fetch thread data from the service for root messages to catch replies
        // not yet loaded in the current page
        foreach (var msg in _messages.Where(m => m.ReplyToId is null))
        {
            if (!_threadSummaries.ContainsKey(msg.Id))
            {
                try
                {
                    var thread = await ChatService.GetThreadAsync(msg.Id);
                    if (thread.Count > 0)
                    {
                        _threadSummaries[msg.Id] = new ThreadSummary(
                            msg.Id,
                            thread.Count,
                            thread.Max(r => r.SentAt));
                    }
                }
                catch
                {
                    // Thread may not exist
                }
            }
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        return _threadSummaries.GetValueOrDefault(messageId);
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingMore || _messages is null || _activeChannel is null) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.AddRange(older);
        }

        _loadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannel.Id, _newMessageText.Trim(), null);
        _messages ??= new();
        _messages.Insert(0, sent);
        _newMessageText = string.Empty;
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        _activeThreadRootId = rootMessageId;
        _threadRootMessage = _messages?.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadReplyText = string.Empty;
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _activeThreadRootId = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _activeChannel is null || _activeThreadRootId is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, _threadReplyText.Trim(), _activeThreadRootId);
        _threadReplies ??= new();
        _threadReplies.Add(reply);
        _threadReplyText = string.Empty;

        _threadSummaries[_activeThreadRootId.Value] = new ThreadSummary(
            _activeThreadRootId.Value,
            _threadReplies.Count,
            reply.SentAt);
    }

    private async Task OnThreadReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        if (_activeChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _messages?.Count ?? PageSize);
        }

        if (_threadOpen && _activeThreadRootId is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_activeThreadRootId.Value);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 172800 => "yesterday",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 50 ? string.Concat(description.AsSpan(0, 47), "...") : description;
    }
}

